            if ca == 0:
                continue
            for b in range(0, 10):
                cb = freq[b]
                if b == a:
                    if cb < 2:
                        continue
                else:
                    if cb == 0:
                        continue
                for c in evens:
                    cc = freq[c]
                    # check availability depending on equalities among a,b,c
                    if a == b == c:
                        if cc >= 3:
                            res.append(100 * a + 10 * b + c)
                    elif a == b:
                        if ca >= 2 and cc >= 1:
                            res.append(100 * a + 10 * b + c)
                    elif a == c:
                        if ca >= 2 and cb >= 1:
                            res.append(100 * a + 10 * b + c)
                    elif b == c:
                        if cb >= 2 and ca >= 1:
                            res.append(100 * a + 10 * b + c)
                    else:
                        # all distinct
                        if ca and cb and cc:
                            res.append(100 * a + 10 * b + c)
        return res

Why this is faster
- We count digits once O(n).
- Triple nested loops iterate at most 9*10*5 = 450 times — tiny and constant.
- No Counter construction or digit extraction per candidate.
- All checks are just integer comparisons and array access.

This is much faster in practice than the original approach and uses very little memory.

